    HomeiiConfigValidators.assertValueInList(config.layout_mode, "layout_mode", ["auto", "mobile", "tablet"]);
    HomeiiConfigValidators.assertValueInList(config.settings_source, "settings_source", ["device", "visual", "ui", "card"]);
