const HomeiiStateFoundation = Object.freeze({
  createBaseBrowserState() {
    return {
      view: "home",
      query: "",
      nowPlayingQuery: "",
      selectedPlayer: null,
      players: [],
      wsReady: false,
      queueVisible: false,
      queueItems: [],
      queueMutationPendingUntil: 0,
      queueMutationExpectedSignature: "",
      maQueueState: null,
      lang: "en",
      pendingGroupSelections: [],
      nowPlayingUri: "",
      renderToken: 0,
      playerModalOpen: false,
      hasAutoSelectedPlayer: false,
      cardTheme: "auto",
      performanceProfile: "full",
      performanceMode: false,
      performanceModeLocalOverride: false,
      modalMode: "players",
      sidePanelToken: 0,
      immersiveNowPlayingOpen: false,
      lyricsOpen: false,
      lyricsLines: [],
      lyricsActiveIndex: -1,
      tracksLayout: "list",
      queueActionPending: false,
      emptyQuickShelfItems: [],
      emptyQuickShelfMode: "default",
      forceRadioHero: false,
      quickMixPendingUntil: 0,
      quickMixPendingEntry: null,
      quickMixRecommendationItems: [],
      likedSelectionMode: false,
      likedSelectedUris: [],
      mobileLibraryDetail: null,
      mobileLibraryDetailParentPage: "",
      controlRoomOpen: false,
      controlRoomSelectedPlayers: [],
      controlRoomLibraryQuery: "",
      controlRoomLibraryResults: [],
      controlRoomLibraryLoading: false,
      controlRoomTransferSource: "",
      controlRoomTransferTarget: "",
      controlRoomPanel: "",
      controlRoomVisiblePlayers: [],
      controlRoomCustomScenes: [],
      controlRoomSceneName: "",
      controlRoomRevealThisDevicePending: false,
      controlRoomRenderedHtml: "",
      controlRoomRenderSignature: "",
      activePlayerHelperLastValue: undefined,
    };
  },
  normalizeSettingsSource(value) {
    const normalized = String(value || "").trim().toLowerCase();
    if (["card", "visual", "config", "card_config", "editor"].includes(normalized)) return "card";
    if (["ui", "device", "local", "in_card"].includes(normalized)) return "ui";
    return "ui";
  },
  usesVisualSettings(config) {
    return HomeiiStateFoundation.normalizeSettingsSource(config?.settings_source) === "card";
  },
  mobileCompactModeEnabled(state) {
    return !!state?.mobileCompactMode;
  },
  mobileCompactWidgetMode(state) {
    const mode = String(state?.mobileCompactWidgetMode || "auto").trim().toLowerCase();
    return ["auto", "full", "mini"].includes(mode) ? mode : "auto";
  },
  mobileShowUpNextEnabled(state) {
    return state?.mobileShowUpNext === true;
  },
  performanceProfile(state) {
    const profile = String(state?.performanceProfile || "").trim().toLowerCase();
    if (["full", "high", "low", "ultra_lite"].includes(profile)) return profile;
    return state?.performanceMode === true ? "low" : "full";
  },
  performanceModeEnabled(state) {
    return ["low", "ultra_lite"].includes(HomeiiStateFoundation.performanceProfile(state));
  },
  performanceUltraLiteEnabled(state) {
    return HomeiiStateFoundation.performanceProfile(state) === "ultra_lite";
  },
  mobileDynamicThemeMode(state) {
    const profile = HomeiiStateFoundation.performanceProfile(state);
    if (profile === "low" || profile === "ultra_lite") return "off";
    const mode = String(state?.mobileDynamicThemeMode || "auto").toLowerCase();
    const normalized = ["off", "auto", "strong"].includes(mode) ? mode : "auto";
    return profile === "high" && normalized === "strong" ? "auto" : normalized;
  },
  mobileBackgroundMotionMode(state) {
    const profile = HomeiiStateFoundation.performanceProfile(state);
    if (profile === "low" || profile === "ultra_lite") return "off";
    const mode = String(state?.mobileBackgroundMotionMode || "subtle").toLowerCase();
    const normalized = ["off", "subtle", "strong", "extreme"].includes(mode) ? mode : "subtle";
    return profile === "high" && ["strong", "extreme"].includes(normalized) ? "subtle" : normalized;
  },
  backgroundMotionEnabled(state) {
    return HomeiiStateFoundation.mobileBackgroundMotionMode(state) !== "off";
  },
  backgroundMotionAmount(state) {
    const mode = HomeiiStateFoundation.mobileBackgroundMotionMode(state);
    if (mode === "extreme") return "1.85";
    if (mode === "strong") return "1.35";
    return "1";
  },
  isCompactTileMode(state) {
    return HomeiiStateFoundation.mobileCompactModeEnabled(state) && !state?.mobileCompactExpanded;
  },
});

const HomeiiMobileSettingsFoundation = Object.freeze({
  clampMobileFontScale(value) {
    return Math.max(0.5, Math.min(1.5, Number(value || 1) || 1));
  },
  clampMobileIconScale(value) {
    return Math.max(0.8, Math.min(1.25, Number(value || 1) || 1));
  },
  clampMobileVolumeStepPercent(value) {
    return Math.round(HomeiiMobileSettingsFoundation.clampNumber(value, 5, { min: 1, max: 10 }));
  },
  normalizeEnum(value, allowedValues, fallbackValue) {
    const normalized = String(value || "").trim().toLowerCase();
    return allowedValues.includes(normalized) ? normalized : fallbackValue;
  },
  normalizePerformanceProfile(value, legacyPerformanceMode = false) {
    const normalized = HomeiiMobileSettingsFoundation.normalizeEnum(value, ["full", "high", "low", "ultra_lite"], "");
    if (normalized) return normalized;
    return legacyPerformanceMode === true ? "low" : "full";
  },
  normalizeStringArray(value) {
    return Array.isArray(value)
      ? value.map((entry) => String(entry || "").trim()).filter(Boolean)
      : [];
  },
  normalizeEntityList(value) {
    const source = Array.isArray(value)
      ? value
      : String(value || "").split(/[\s,]+/);
    const next = [];
    source.map((entry) => String(entry || "").trim()).filter(Boolean).forEach((entityId) => {
      if (!next.includes(entityId)) next.push(entityId);
    });
    return next;
  },
  parseAmbientLightPlayerMap(value) {
    const groups = [];
    const byPlayer = new Map();
    HomeiiMobileSettingsFoundation.normalizeStringArray(value).forEach((mapping) => {
      const parts = String(mapping || "").split(/\s*(?:=>|=|:)\s*/);
      const player = String(parts[0] || "").trim();
      const lights = HomeiiMobileSettingsFoundation.normalizeEntityList(parts.slice(1).join(","))
        .filter((entityId) => entityId.startsWith("light."));
      if (!player.startsWith("media_player.") || !lights.length) return;
      if (!byPlayer.has(player)) {
        const group = { player, lights: [] };
        byPlayer.set(player, group);
        groups.push(group);
      }
      const group = byPlayer.get(player);
      lights.forEach((entityId) => {
        if (!group.lights.includes(entityId)) group.lights.push(entityId);
      });
    });
    return groups;
  },
  formatAmbientLightPlayerMapEntry(player, lights = []) {
    const playerId = String(player || "").trim();
    const lightIds = HomeiiMobileSettingsFoundation.normalizeEntityList(lights)
      .filter((entityId) => entityId.startsWith("light."));
    return playerId && lightIds.length ? `${playerId} = ${lightIds.join(", ")}` : "";
  },
  isColorCapableLightEntity(entity) {
    if (!entity?.entity_id?.startsWith?.("light.")) return false;
    const attributes = entity.attributes || {};
    const colorModes = ["hs", "xy", "rgb", "rgbw", "rgbww"];
    const supportedModes = Array.isArray(attributes.supported_color_modes)
      ? attributes.supported_color_modes.map((mode) => String(mode || "").toLowerCase())
      : [];
    if (supportedModes.some((mode) => colorModes.includes(mode))) return true;
    if (colorModes.includes(String(attributes.color_mode || "").toLowerCase())) return true;
    const supportedFeatures = Number(attributes.supported_features);
    return Number.isFinite(supportedFeatures) && (supportedFeatures & 16) === 16;
  },
  clampPercent(value, fallback = 35, { min = 1, max = 100 } = {}) {
    const number = Number(value);
    const safe = Number.isFinite(number) ? number : fallback;
    return Math.max(min, Math.min(max, safe));
  },
  clampSeconds(value, fallback = 3, { min = 0, max = 300 } = {}) {
    const number = Number(value);
    const safe = Number.isFinite(number) ? number : fallback;
    return Math.max(min, Math.min(max, safe));
  },
  clampNumber(value, fallback = 1, { min = 0, max = 1 } = {}) {
    const number = Number(value);
    const safe = Number.isFinite(number) ? number : fallback;
    return Math.max(min, Math.min(max, safe));
  },
  normalizeScreensaverClockMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["digital", "analog"], "digital");
  },
  normalizeScreensaverControlButtons(items, fallbackItems = []) {
    const allowed = new Set(["previous", "play_pause", "next", "mute", "power", "like", "voice"]);
    const fallback = HomeiiMobileSettingsFoundation.normalizeStringArray(fallbackItems).filter((item) => allowed.has(item));
    const hasExplicitItems = Array.isArray(items);
    const source = hasExplicitItems ? items : fallback;
    const cleaned = [];
    HomeiiMobileSettingsFoundation.normalizeStringArray(source).forEach((item) => {
      if (allowed.has(item) && !cleaned.includes(item)) cleaned.push(item);
    });
    return cleaned.length ? cleaned : (hasExplicitItems ? [] : fallback);
  },
  normalizePowerButtonAction(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["stop_player", "toggle", "turn_on", "turn_off", "scene", "script"], "stop_player");
  },
  normalizeAuxiliaryButtonIcon(value) {
    const icon = String(value || "").trim();
    if (/^[a-z0-9_-]+:[a-z0-9_-]+$/i.test(icon)) return icon;
    return HomeiiMobileSettingsFoundation.normalizeEnum(icon, ["power", "home", "speaker", "music_note", "wand", "grid", "settings", "heart_outline", "play", "stop", "radio", "timer", "info"], "power");
  },
  normalizePlayerSortMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["default", "alphabetical", "custom"], "default");
  },
  normalizePlayerOrderEntities(config = {}, limit = 50) {
    const ordered = [];
    const dynamicLimit = Object.keys(config || {}).reduce((max, key) => {
      const match = /^player_order_entity_(\d+)$/.exec(key);
      return match ? Math.max(max, Number(match[1]) || 0) : max;
    }, limit);
    for (let index = 1; index <= dynamicLimit; index += 1) {
      const entityId = String(config?.[`player_order_entity_${index}`] || "").trim();
      if (entityId && !ordered.includes(entityId)) ordered.push(entityId);
    }
    HomeiiMobileSettingsFoundation.normalizeStringArray(config?.player_order_entities).forEach((entityId) => {
      if (!ordered.includes(entityId)) ordered.push(entityId);
    });
    return ordered;
  },
  normalizeAuxiliaryButtons(config = {}, limit = 4) {
    const buttons = [{
      enabled: config.power_button_enabled === true,
      name: String(config.power_button_name || "").trim(),
      icon: HomeiiMobileSettingsFoundation.normalizeAuxiliaryButtonIcon(config.power_button_icon || "power"),
      action: HomeiiMobileSettingsFoundation.normalizePowerButtonAction(config.power_button_action),
      entity: String(config.power_button_entity || "").trim(),
    }];
    for (let index = 2; index <= limit; index += 1) {
      buttons.push({
        enabled: config[`aux_button_${index}_enabled`] === true,
        name: String(config[`aux_button_${index}_name`] || "").trim(),
        icon: HomeiiMobileSettingsFoundation.normalizeAuxiliaryButtonIcon(config[`aux_button_${index}_icon`] || "power"),
        action: HomeiiMobileSettingsFoundation.normalizePowerButtonAction(config[`aux_button_${index}_action`]),
        entity: String(config[`aux_button_${index}_entity`] || "").trim(),
      });
    }
    return buttons;
  },
  normalizeHomeShortcutPath(value, { leadingSlash = false } = {}) {
    const normalized = String(value || "/").trim() || "/";
    if (!leadingSlash) return normalized;
    if (normalized.startsWith("/")) return normalized;
    return `/${normalized.replace(/^\/+/, "")}`;
  },
  normalizeMobileFooterMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["icon", "text", "both"], "both");
  },
  normalizeMobileMicMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["on", "off", "smart"], "smart");
  },
  normalizeVoiceAssistantMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["hybrid", "music", "assist"], "hybrid");
  },
  normalizeMobileVolumeMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["always", "button"], "button");
  },
  normalizeMobileCompactWidgetMode(value) {
    return HomeiiMobileSettingsFoundation.normalizeEnum(value, ["auto", "full", "mini"], "auto");
  },
  normalizeMobileLibraryDefaultLayout(value, fallback = "list") {
    return HomeiiMobileSettingsFoundation.normalizeEnum(
      value,
      ["grid", "list"],
      HomeiiMobileSettingsFoundation.normalizeEnum(fallback, ["grid", "list"], "list")
    );
  },
  normalizePinnedPlayerEntityList(value) {
    const next = [];
    HomeiiMobileSettingsFoundation.normalizeStringArray(value).forEach((entityId) => {
      if (!next.includes(entityId)) next.push(entityId);
    });
    return next;
  },
  normalizePinnedPlayerEntities(config = {}) {
    const explicitEntities = HomeiiMobileSettingsFoundation.normalizeStringArray(config?.pinned_player_entities);
    if (explicitEntities.length) return HomeiiMobileSettingsFoundation.normalizePinnedPlayerEntityList(explicitEntities);
    const singleEntity = String(config?.pinned_player_entity || "").trim();
    return HomeiiMobileSettingsFoundation.normalizePinnedPlayerEntityList(singleEntity ? [singleEntity] : []);
  },
  normalizeExcludedPlayerEntities(config = {}) {
    return HomeiiMobileSettingsFoundation.normalizePinnedPlayerEntityList(config?.excluded_player_entities);
  },
  normalizeMobileMainBarItems(items, {
    usesVisualSettings = false,
    hidePlayers = false,
    fallbackItems = [],
  } = {}) {
    const allowed = new Set(["search", "library", "players", "actions", "settings", "theme"]);
    const baseFallback = HomeiiMobileSettingsFoundation.normalizeStringArray(fallbackItems);
    const fallback = usesVisualSettings
      ? baseFallback.filter((item) => item !== "settings")
      : baseFallback;
    const source = Array.isArray(items) && items.length ? items : fallback;
    const cleaned = HomeiiMobileSettingsFoundation.normalizeStringArray(source)
      .filter((item) => allowed.has(item))
      .filter((item) => !(usesVisualSettings && item === "settings"))
      .filter((item) => !(hidePlayers && item === "players"));
    const normalizedFallback = fallback.filter((item) => !(hidePlayers && item === "players"));
    const normalized = cleaned.length ? cleaned : normalizedFallback;
    if (!usesVisualSettings && !normalized.includes("settings")) normalized.push("settings");
    return normalized;
  },
  normalizeMobileQuickActions(items, fallbackItems = []) {
    const allowed = new Set(["home", "search", "timer", "like", "lyrics", "queue", "radio", "voice", "history", "info", "disconnect_all"]);
    const fallback = HomeiiMobileSettingsFoundation.normalizeStringArray(fallbackItems).filter((item) => allowed.has(item));
    const hasExplicitItems = Array.isArray(items);
    const source = hasExplicitItems ? items : fallback;
    const cleaned = [];
    HomeiiMobileSettingsFoundation.normalizeStringArray(source).forEach((item) => {
      if (allowed.has(item) && !cleaned.includes(item)) cleaned.push(item);
    });
    return cleaned.length ? cleaned : (hasExplicitItems ? [] : fallback);
  },
  normalizeMobileQuickActionSlots(config = {}, selectedItems = []) {
    const allowed = new Set(["home", "search", "timer", "like", "lyrics", "queue", "radio", "voice", "history", "info", "disconnect_all"]);
    const selected = HomeiiMobileSettingsFoundation.normalizeStringArray(selectedItems).filter((item) => allowed.has(item));
    const ordered = [];
    for (let index = 1; index <= 10; index += 1) {
      const item = String(config?.[`mobile_quick_action_${index}`] || "").trim();
      if (!allowed.has(item) || !selected.includes(item) || ordered.includes(item)) continue;
      ordered.push(item);
    }
    selected.forEach((item) => {
      if (!ordered.includes(item)) ordered.push(item);
    });
    return ordered;
  },
  normalizeMobileLibraryTabs(tabs, fallbackTabs = []) {
    const allowed = new Set(["library_playlists", "library_artists", "library_albums", "library_tracks", "library_radio", "library_podcasts", "library_liked", "library_search"]);
    const fallback = HomeiiMobileSettingsFoundation.normalizeStringArray(fallbackTabs);
    const source = Array.isArray(tabs) && tabs.length ? tabs : fallback;
    const cleaned = HomeiiMobileSettingsFoundation.normalizeStringArray(source).filter((tab) => allowed.has(tab));
    const normalized = cleaned.length ? cleaned : fallback;
    return normalized.includes("library_search")
      ? ["library_search", ...normalized.filter((tab) => tab !== "library_search")]
      : normalized;
  },
  normalizeVisualMobileState(config = {}, {
    normalizeClockTime = (value, fallback) => String(value || fallback || ""),
    normalizeNightModeDays = (value) => Array.isArray(value) ? value : [0, 1, 2, 3, 4, 5, 6],
    defaultLibraryTabs = [],
    defaultMainBarItems = [],
    defaultQuickActions = [],
    defaultAnnouncementPresets = [],
  } = {}) {
    const screensaverControlFallback = config.screensaver_controls_enabled === true ? ["previous", "next"] : [];
    const performanceProfile = HomeiiMobileSettingsFoundation.normalizePerformanceProfile(config.performance_profile, config.performance_mode);
    return {
      lang: String(config.language || "en"),
      cardTheme: String(config.theme_mode || "auto"),
      performanceProfile,
      performanceMode: ["low", "ultra_lite"].includes(performanceProfile),
      mobileCustomColor: String(config.mobile_custom_color || "#f5a623"),
      mobileDynamicThemeMode: HomeiiMobileSettingsFoundation.normalizeEnum(config.mobile_dynamic_theme_mode, ["off", "auto", "strong"], "auto"),
      mobileBackgroundMotionMode: HomeiiMobileSettingsFoundation.normalizeEnum(config.mobile_background_motion_mode, ["off", "subtle", "strong", "extreme"], "subtle"),
      mobileCustomTextTone: String(config.mobile_custom_text_tone || "light") === "dark" ? "dark" : "light",
      mobileFontScale: HomeiiMobileSettingsFoundation.clampMobileFontScale(config.mobile_font_scale),
      mobileIconScale: HomeiiMobileSettingsFoundation.clampMobileIconScale(config.mobile_icon_scale),
      mobileNightMode: HomeiiMobileSettingsFoundation.normalizeEnum(config.night_mode, ["off", "auto", "on"], "off"),
      mobileNightModeStart: normalizeClockTime(config.night_mode_auto_start || "22:00", "22:00"),
      mobileNightModeEnd: normalizeClockTime(config.night_mode_auto_end || "06:00", "06:00"),
      mobileNightModeDays: normalizeNightModeDays(config.night_mode_days),
      mobileCompactMode: !!config.mobile_compact_mode,
      mobileCompactWidgetMode: HomeiiMobileSettingsFoundation.normalizeMobileCompactWidgetMode(config.mobile_compact_widget_mode),
      mobileLibraryDefaultLayout: HomeiiMobileSettingsFoundation.normalizeMobileLibraryDefaultLayout(config.mobile_library_default_layout, "list"),
      mobileShowUpNext: config.mobile_show_up_next === true,
      mobileFooterSearchEnabled: !!config.mobile_footer_search_enabled,
      mobileStudioShortcutEnabled: config.mobile_studio_shortcut !== false,
      mobileFooterMode: HomeiiMobileSettingsFoundation.normalizeMobileFooterMode(config.mobile_footer_mode),
      mobileHomeShortcutEnabled: !!config.mobile_home_shortcut,
      mobileHomeShortcutPath: HomeiiMobileSettingsFoundation.normalizeHomeShortcutPath(config.mobile_home_shortcut_path),
      mobileVolumeMode: HomeiiMobileSettingsFoundation.normalizeMobileVolumeMode(config.mobile_volume_mode),
      mobileVolumeStepButtonsEnabled: config.mobile_volume_step_buttons === true,
      mobileVolumeStepPercent: HomeiiMobileSettingsFoundation.clampMobileVolumeStepPercent(config.mobile_volume_step_percent),
      mobileMicMode: HomeiiMobileSettingsFoundation.normalizeMobileMicMode(config.mobile_mic_mode),
      voiceAssistantEnabled: config.voice_assistant_enabled === true,
      voiceAssistantMode: HomeiiMobileSettingsFoundation.normalizeVoiceAssistantMode(config.voice_assistant_mode),
      voiceAssistantAgentId: String(config.voice_assistant_agent_id || "").trim(),
      voiceAssistantSpeakFeedback: config.voice_assistant_speak_feedback === true,
      mobileLikedMode: HomeiiMobileSettingsFoundation.normalizeEnum(config.mobile_liked_mode, ["ma", "local"], "ma"),
      mobileSwipeMode: HomeiiMobileSettingsFoundation.normalizeEnum(config.mobile_swipe_mode, ["play", "browse"], "browse"),
      mobileRadioBrowserCountry: String(config.mobile_radio_browser_country || "all"),
      mobileLibraryTabs: Array.isArray(config.mobile_library_tabs) && config.mobile_library_tabs.length
        ? config.mobile_library_tabs.slice()
        : HomeiiMobileSettingsFoundation.normalizeStringArray(defaultLibraryTabs),
      mobileMainBarItems: Array.isArray(config.mobile_main_bar_items) && config.mobile_main_bar_items.length
        ? config.mobile_main_bar_items.slice()
        : HomeiiMobileSettingsFoundation.normalizeStringArray(defaultMainBarItems),
      mobileQuickActions: HomeiiMobileSettingsFoundation.normalizeMobileQuickActionSlots(config, HomeiiMobileSettingsFoundation.normalizeMobileQuickActions(
        config.mobile_quick_actions,
        defaultQuickActions,
      )),
      mobileAnnouncementPresets: Array.isArray(config.mobile_announcement_presets) && config.mobile_announcement_presets.length
        ? config.mobile_announcement_presets.slice(0, 3)
        : HomeiiMobileSettingsFoundation.normalizeStringArray(defaultAnnouncementPresets).slice(0, 3),
      mobileAnnouncementVolume: Number.isFinite(Number(config.mobile_announcement_volume))
        ? Math.max(20, Math.min(50, Number(config.mobile_announcement_volume)))
        : 20,
      mobileAnnouncementTtsEntity: String(config.announcement_tts_entity || ""),
      mobileAnnouncementTtsLanguage: String(config.announcement_tts_language || "auto"),
      pinnedPlayerEntities: HomeiiMobileSettingsFoundation.normalizePinnedPlayerEntities(config),
      ambientLightEnabled: config.ambient_light_enabled === true,
      ambientLightEntities: HomeiiMobileSettingsFoundation.normalizeEntityList(config.ambient_light_entities),
      ambientLightPlayerMap: HomeiiMobileSettingsFoundation.normalizeStringArray(config.ambient_light_player_map),
      ambientLightBrightness: HomeiiMobileSettingsFoundation.clampPercent(config.ambient_light_brightness, 35, { min: 1, max: 100 }),
      ambientLightTransition: HomeiiMobileSettingsFoundation.clampSeconds(config.ambient_light_transition, 3, { min: 0, max: 120 }),
      ambientLightCooldown: HomeiiMobileSettingsFoundation.clampSeconds(config.ambient_light_cooldown, 8, { min: 0, max: 120 }),
      screensaverEnabled: config.screensaver_enabled === true,
      screensaverControlsEnabled: config.screensaver_controls_enabled === true,
      screensaverControlButtons: HomeiiMobileSettingsFoundation.normalizeScreensaverControlButtons(config.screensaver_control_buttons, screensaverControlFallback),
      screensaverClockMode: HomeiiMobileSettingsFoundation.normalizeScreensaverClockMode(config.screensaver_clock_mode),
      screensaverTimeoutSeconds: HomeiiMobileSettingsFoundation.clampSeconds(config.screensaver_timeout_seconds, 90, { min: 15, max: 3600 }),
      screensaverMessage: String(config.screensaver_message || ""),
      screensaverClockSize: HomeiiMobileSettingsFoundation.clampNumber(config.screensaver_clock_size, 1, { min: 0.75, max: 1.45 }),
      screensaverClockX: HomeiiMobileSettingsFoundation.clampNumber(config.screensaver_clock_x, 82, { min: 8, max: 92 }),
      screensaverClockY: HomeiiMobileSettingsFoundation.clampNumber(config.screensaver_clock_y, 24, { min: 8, max: 70 }),
      powerButtonEnabled: config.power_button_enabled === true,
      powerButtonName: String(config.power_button_name || "").trim(),
      powerButtonIcon: HomeiiMobileSettingsFoundation.normalizeAuxiliaryButtonIcon(config.power_button_icon || "power"),
      powerButtonAction: HomeiiMobileSettingsFoundation.normalizePowerButtonAction(config.power_button_action),
      powerButtonEntity: String(config.power_button_entity || "").trim(),
      auxiliaryButtons: HomeiiMobileSettingsFoundation.normalizeAuxiliaryButtons(config).slice(1),
      excludedPlayerEntities: HomeiiMobileSettingsFoundation.normalizeExcludedPlayerEntities(config),
      playerSortMode: HomeiiMobileSettingsFoundation.normalizePlayerSortMode(config.player_sort_mode),
      playerOrderEntities: HomeiiMobileSettingsFoundation.normalizePlayerOrderEntities(config),
      discoveryModeEnabled: config.discovery_mode_enabled !== false,
    };
  },
});

const HomeiiResponsiveFoundation = Object.freeze({
  resolveLayoutMode(layoutMode, {
    rectWidth = 0,
    hostWidth = 0,
    viewportWidth = 0,
  } = {}, tabletBreakpoint = 980) {
    const normalized = String(layoutMode || "auto").trim().toLowerCase();
    if (normalized === "mobile" || normalized === "tablet") return normalized;
    const cardWidth = Math.max(
      Number(rectWidth || 0),
      Number(hostWidth || 0),
    );
    const width = cardWidth > 0 ? cardWidth : Number(viewportWidth || 0);
    return width >= tabletBreakpoint ? "tablet" : "mobile";
  },
  defaultMobileMediaLayout(layoutMode) {
    return layoutMode === "tablet" ? "grid" : "list";
  },
  resolveLayoutProfile({
    width = 0,
    height = 0,
    layoutMode = "mobile",
  } = {}) {
    const measuredWidth = Math.max(0, Number(width || 0));
    const measuredHeight = Math.max(0, Number(height || 0));
    const size = measuredWidth < 380
      ? "xs"
      : measuredWidth < 520
        ? "sm"
        : measuredWidth < 760
          ? "md"
          : measuredWidth < 1100
            ? "lg"
            : "xl";
    const heightSize = measuredHeight > 0 && measuredHeight < 620
      ? "short"
      : measuredHeight >= 900
        ? "tall"
        : "normal";
    const aspect = measuredHeight > 0 && measuredWidth / measuredHeight >= 1.08
      ? "wide"
      : measuredWidth > 0 && measuredHeight / measuredWidth >= 1.18
        ? "portrait"
        : "balanced";
    const tight = measuredHeight > 0 && measuredHeight < 560;
    const compact = size === "xs" || heightSize === "short";
    const roomy = size === "xl" && heightSize === "tall";
    return {
      width: measuredWidth,
      height: measuredHeight,
      layoutMode,
      size,
      heightSize,
      aspect,
      tight,
      compact,
      roomy,
      classes: [
        `size-${size}`,
        `height-${heightSize}`,
        `aspect-${aspect}`,
        tight ? "height-tight" : "",
        compact ? "profile-compact" : "profile-comfort",
        roomy ? "profile-roomy" : "",
      ].filter(Boolean),
    };
  },
  tabletAutoFitEnabled(layoutMode) {
    return layoutMode === "tablet";
  },
  tabletAutoFitDense(layoutMode, {
    showNightRow = false,
    showUpNext = false,
  } = {}) {
    return HomeiiResponsiveFoundation.tabletAutoFitEnabled(layoutMode) && !!(showNightRow || showUpNext);
  },
  resolveTabletAutoFitFlags(layoutMode, {
    showNightRow = false,
    showUpNext = false,
  } = {}) {
    const autoFit = HomeiiResponsiveFoundation.tabletAutoFitEnabled(layoutMode);
    return {
      autoFit,
      showNight: autoFit && !!showNightRow,
      showUpNext: autoFit && !!showUpNext,
      dense: autoFit && !!(showNightRow || showUpNext),
    };
  },
  tabletStabilityModeEnabled({
    layoutMode = "mobile",
    userAgent = "",
    width = 0,
    touchPoints = 0,
  } = {}, tabletBreakpoint = 980) {
    return layoutMode === "tablet"
      && /Android/i.test(String(userAgent || ""))
      && Number(width || 0) >= tabletBreakpoint
      && Number(touchPoints || 0) > 0;
  },
  detectKeyboardLikeResize({
    editingText = false,
    widthDelta = 0,
    heightDelta = 0,
  } = {}) {
    return !!editingText && (
      (Number(widthDelta || 0) < 120 && Number(heightDelta || 0) > 18)
      || (Number(widthDelta || 0) < 8 && Number(heightDelta || 0) > 0)
    );
  },
  resolveResizeStrategy({
    previousWidth = 0,
    currentWidth = 0,
    previousHeight = 0,
    currentHeight = 0,
    editingText = false,
    tabletStabilityMode = false,
  } = {}, tabletBreakpoint = 980) {
    const widthDelta = Math.abs(Number(currentWidth || 0) - Number(previousWidth || 0));
    const heightDelta = Math.abs(Number(currentHeight || 0) - Number(previousHeight || 0));
    const keyboardLikeResize = HomeiiResponsiveFoundation.detectKeyboardLikeResize({
      editingText,
      widthDelta,
      heightDelta,
    });
    const previousTablet = Number(previousWidth || 0) >= tabletBreakpoint;
    const currentTablet = Number(currentWidth || 0) >= tabletBreakpoint;
    const widthThreshold = tabletStabilityMode ? 140 : 48;
    const heightThreshold = tabletStabilityMode ? 180 : 48;
    const softSync = !keyboardLikeResize
      && previousTablet === currentTablet
      && widthDelta < widthThreshold
      && heightDelta < heightThreshold;
    return {
      widthDelta,
      heightDelta,
      keyboardLikeResize,
      previousTablet,
      currentTablet,
      widthThreshold,
      heightThreshold,
      softSync,
    };
  },
});

const HomeiiPaletteFoundation = Object.freeze({
  clampRgbByte(value) {
    return Math.max(0, Math.min(255, Math.round(Number(value) || 0)));
  },
  normalizeRgbTuple(value, fallback = [245, 166, 35]) {
    if (Array.isArray(value) && value.length >= 3) {
      return value.slice(0, 3).map((entry) => HomeiiPaletteFoundation.clampRgbByte(entry));
    }
    if (typeof value === "string") {
      const parts = value.trim().split(/[,\s]+/).map((entry) => Number(entry));
      if (parts.length >= 3 && parts.every((entry) => Number.isFinite(entry))) {
        return parts.slice(0, 3).map((entry) => HomeiiPaletteFoundation.clampRgbByte(entry));
      }
    }
    return fallback.map((entry) => HomeiiPaletteFoundation.clampRgbByte(entry));
  },
  hexToRgbTuple(value, fallback = [245, 166, 35]) {
    const hex = String(value || "#f5a623").replace("#", "").trim();
    const normalized = hex.length === 3
      ? hex.split("").map((char) => char + char).join("")
      : hex.padEnd(6, "0").slice(0, 6);
    const tuple = [
      parseInt(normalized.slice(0, 2), 16),
      parseInt(normalized.slice(2, 4), 16),
      parseInt(normalized.slice(4, 6), 16),
    ];
    if (tuple.every((entry) => Number.isFinite(entry))) {
      return tuple.map((entry) => HomeiiPaletteFoundation.clampRgbByte(entry));
    }
    return HomeiiPaletteFoundation.normalizeRgbTuple(fallback);
  },
  rgbTupleToString(tuple = [245, 166, 35]) {
    const [r, g, b] = HomeiiPaletteFoundation.normalizeRgbTuple(tuple);
    return `${r} ${g} ${b}`;
  },
  rgbTupleToHex(tuple = [245, 166, 35]) {
    return `#${HomeiiPaletteFoundation.normalizeRgbTuple(tuple)
      .map((entry) => HomeiiPaletteFoundation.clampRgbByte(entry).toString(16).padStart(2, "0"))
      .join("")}`;
  },
  mixRgb(left = [245, 166, 35], right = [255, 255, 255], ratio = 0.5) {
    const weight = Math.max(0, Math.min(1, Number(ratio) || 0));
    const from = HomeiiPaletteFoundation.normalizeRgbTuple(left);
    const to = HomeiiPaletteFoundation.normalizeRgbTuple(right);
    return from.map((entry, index) => HomeiiPaletteFoundation.clampRgbByte(entry + ((to[index] - entry) * weight)));
  },
  rgbToHsl(tuple = [245, 166, 35]) {
    let [r, g, b] = HomeiiPaletteFoundation.normalizeRgbTuple(tuple).map((entry) => entry / 255);
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);
    const lightness = (max + min) / 2;
    if (max === min) return [0, 0, lightness];
    const delta = max - min;
    const saturation = lightness > 0.5 ? delta / (2 - max - min) : delta / (max + min);
    let hue = 0;
    switch (max) {
      case r: hue = ((g - b) / delta) + (g < b ? 6 : 0); break;
      case g: hue = ((b - r) / delta) + 2; break;
      default: hue = ((r - g) / delta) + 4; break;
    }
    return [hue / 6, saturation, lightness];
  },
  hslToRgb(hue = 0, saturation = 0, lightness = 0.5) {
    const h = ((Number(hue) % 1) + 1) % 1;
    const s = Math.max(0, Math.min(1, Number(saturation) || 0));
    const l = Math.max(0, Math.min(1, Number(lightness) || 0));
    if (s === 0) {
      const value = HomeiiPaletteFoundation.clampRgbByte(l * 255);
      return [value, value, value];
    }
    const hueToRgb = (p, q, t) => {
      let value = t;
      if (value < 0) value += 1;
      if (value > 1) value -= 1;
      if (value < 1 / 6) return p + ((q - p) * 6 * value);
      if (value < 1 / 2) return q;
      if (value < 2 / 3) return p + ((q - p) * (2 / 3 - value) * 6);
      return p;
    };
    const q = l < 0.5 ? l * (1 + s) : (l + s - (l * s));
    const p = (2 * l) - q;
    return [
      HomeiiPaletteFoundation.clampRgbByte(hueToRgb(p, q, h + (1 / 3)) * 255),
      HomeiiPaletteFoundation.clampRgbByte(hueToRgb(p, q, h) * 255),
      HomeiiPaletteFoundation.clampRgbByte(hueToRgb(p, q, h - (1 / 3)) * 255),
    ];
  },
  tunePaletteColor(tuple = [245, 166, 35], options = {}) {
    const [hue, saturation, lightness] = HomeiiPaletteFoundation.rgbToHsl(tuple);
    const minSat = Number(options.minSaturation ?? 0.42);
    const minLight = Number(options.minLightness ?? 0.42);
    const maxLight = Number(options.maxLightness ?? 0.6);
    const sat = Math.max(minSat, saturation);
    const light = Math.max(minLight, Math.min(maxLight, lightness));
    return HomeiiPaletteFoundation.hslToRgb(hue, sat, light);
  },
  isRgbTupleDark(tuple = [245, 166, 35], threshold = 0.58) {
    const [r, g, b] = HomeiiPaletteFoundation.normalizeRgbTuple(tuple);
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance < Number(threshold || 0.58);
  },
  dynamicThemeStrengthValue(mode = "auto") {
    return String(mode || "").toLowerCase() === "strong" ? "1.35" : "1";
  },
  buildDynamicThemePalette({
    baseTuple = [245, 166, 35],
    vividTuple = [245, 166, 35],
    mode = "auto",
  } = {}) {
    const normalizedMode = String(mode || "auto").toLowerCase();
    const strong = normalizedMode === "strong";
    const base = HomeiiPaletteFoundation.normalizeRgbTuple(baseTuple);
    const accent = HomeiiPaletteFoundation.tunePaletteColor(vividTuple, {
      minSaturation: strong ? 0.58 : 0.46,
      minLightness: 0.42,
      maxLightness: strong ? 0.56 : 0.6,
    });
    const surface = HomeiiPaletteFoundation.mixRgb(base, accent, strong ? 0.32 : 0.2);
    const glow = HomeiiPaletteFoundation.mixRgb(accent, [255, 255, 255], strong ? 0.12 : 0.2);
    return {
      accent: HomeiiPaletteFoundation.rgbTupleToHex(accent),
      accent_rgb: HomeiiPaletteFoundation.rgbTupleToString(accent),
      surface_rgb: HomeiiPaletteFoundation.rgbTupleToString(surface),
      glow_rgb: HomeiiPaletteFoundation.rgbTupleToString(glow),
    };
  },
  resolveActiveAccentColor(palette = null, customColor = "#f5a623") {
    return palette?.accent || String(customColor || "#f5a623");
  },
  resolveActiveAccentRgb(palette = null, customColor = "#f5a623") {
    return palette?.accent_rgb || HomeiiPaletteFoundation.rgbTupleToString(HomeiiPaletteFoundation.hexToRgbTuple(customColor));
  },
});

const HomeiiNightFoundation = Object.freeze({
  normalizeNightMode(value) {
    const mode = String(value || "auto").toLowerCase();
    return ["off", "auto", "on"].includes(mode) ? mode : "auto";
  },
  normalizeClockTime(value, fallback = "22:00") {
    const match = String(value || "").trim().match(/^(\d{1,2})(?::(\d{1,2}))?$/);
    if (!match) return fallback;
    const hours = Math.max(0, Math.min(23, Number(match[1]) || 0));
    const minutes = Math.max(0, Math.min(59, Number(match[2] ?? 0) || 0));
    return `${String(hours).padStart(2, "0")}:${String(minutes).padStart(2, "0")}`;
  },
  clockMinutesOfDay(value, fallback = "22:00") {
    const normalized = HomeiiNightFoundation.normalizeClockTime(value, fallback);
    const [hours, minutes] = normalized.split(":").map((part) => Number(part) || 0);
    return (hours * 60) + minutes;
  },
  defaultNightModeDays() {
    return [0, 1, 2, 3, 4, 5, 6];
  },
  normalizeNightModeDays(value, fallbackDays = [0, 1, 2, 3, 4, 5, 6]) {
    let source = value;
    if (typeof source === "string") {
      const raw = source.trim();
      if (!raw) return [...fallbackDays];
      try {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) source = parsed;
      } catch (_) {
        source = raw.split(/[,\s]+/);
      }
    }
    const normalized = Array.isArray(source)
      ? source
          .map((entry) => Number(entry))
          .filter((entry) => Number.isInteger(entry) && entry >= 0 && entry <= 6)
      : [];
    const unique = Array.from(new Set(normalized)).sort((a, b) => a - b);
    return unique.length ? unique : [...fallbackDays];
  },
  resolveNightModeWindow(start, end, defaults = {}) {
    const fallbackStart = defaults.start || "22:00";
    const fallbackEnd = defaults.end || "06:00";
    return {
      start: HomeiiNightFoundation.normalizeClockTime(start || fallbackStart, fallbackStart),
      end: HomeiiNightFoundation.normalizeClockTime(end || fallbackEnd, fallbackEnd),
    };
  },
  isMinutesInsideWindow(minutes, startMinutes, endMinutes) {
    if (startMinutes === endMinutes) return true;
    if (startMinutes < endMinutes) {
      return minutes >= startMinutes && minutes < endMinutes;
    }
    return minutes >= startMinutes || minutes < endMinutes;
  },
  isNightModeActive({
    mode = "auto",
    start = "22:00",
    end = "06:00",
    days = [0, 1, 2, 3, 4, 5, 6],
    date = new Date(),
  } = {}) {
    const normalizedMode = HomeiiNightFoundation.normalizeNightMode(mode);
    if (normalizedMode === "off") return false;
    if (normalizedMode === "on") return true;
    const nowMinutes = (date.getHours() * 60) + date.getMinutes();
    const startMinutes = HomeiiNightFoundation.clockMinutesOfDay(start, "22:00");
    const endMinutes = HomeiiNightFoundation.clockMinutesOfDay(end, "06:00");
    if (!HomeiiNightFoundation.isMinutesInsideWindow(nowMinutes, startMinutes, endMinutes)) return false;
    const enabledDays = new Set(HomeiiNightFoundation.normalizeNightModeDays(days));
    const currentDay = Number(date.getDay());
    if (startMinutes === endMinutes || startMinutes < endMinutes) {
      return enabledDays.has(currentDay);
    }
    const windowOwnerDay = nowMinutes >= startMinutes ? currentDay : ((currentDay + 6) % 7);
    return enabledDays.has(windowOwnerDay);
  },
  sleepTimerRemainingMs(targetAt, now = Date.now()) {
    const target = Number(targetAt || 0);
    if (!target || target <= now) return 0;
    return target - now;
  },
  sleepTimerRemainingLabel(remainingMs) {
    const remaining = Number(remainingMs || 0);
    if (!remaining) return "";
    const totalMinutes = Math.max(1, Math.ceil(remaining / 60000));
    if (totalMinutes < 60) return `${totalMinutes}m`;
    const hours = Math.floor(totalMinutes / 60);
    const minutes = totalMinutes % 60;
    return minutes ? `${hours}h ${minutes}m` : `${hours}h`;
  },
  sleepTimerFooterLabel(remainingMs) {
    const remaining = Number(remainingMs || 0);
    if (!remaining) return "";
    const totalSeconds = Math.max(0, Math.ceil(remaining / 1000));
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;
    return hours > 0
      ? `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`
      : `${minutes}:${String(seconds).padStart(2, "0")}`;
  },
  normalizeSleepTimerOrigin(source = "") {
    return String(source || "").toLowerCase() === "night" ? "night" : "";
  },
  sleepTimerStartedFromNightMode(remainingMs, origin = "") {
    return Number(remainingMs || 0) > 0 && HomeiiNightFoundation.normalizeSleepTimerOrigin(origin) === "night";
  },
  sleepTimerChipVisible(remainingMs, origin = "") {
    return Number(remainingMs || 0) > 0;
  },
  createSleepTimerTargetAt(minutes, now = Date.now()) {
    const amount = Math.max(1, Number(minutes) || 0);
    return Number(now || 0) + (amount * 60000);
  },
  extendSleepTimerTargetAt(existingTargetAt, minutes, now = Date.now()) {
    const amount = Math.max(1, Number(minutes) || 0);
    const base = HomeiiNightFoundation.sleepTimerRemainingMs(existingTargetAt, now)
      ? Number(existingTargetAt || 0)
      : Number(now || 0);
    return Math.max(base, Number(now || 0)) + (amount * 60000);
  },
  nextSleepTimerStep(currentRemainingMs, steps = [15, 30, 45, 60, 0]) {
    const remaining = Number(currentRemainingMs || 0);
    if (!remaining) return Number(steps[0] || 15);
    const currentMinutes = Math.max(1, Math.ceil(remaining / 60000));
    return steps.find((value) => value > currentMinutes) ?? 0;
  },
});

const HomeiiMediaQueueFoundation = Object.freeze({
  normalizeComparableText(value = "") {
    return String(value || "").trim().toLowerCase();
  },
  normalizeFiniteNumber(value) {
    return value !== "" && value !== null && value !== undefined ? Number(value) : NaN;
  },
  parseMediaReference(uri = "", fallbackType = "track") {
    const value = String(uri || "").trim();
    const fallback = {
      uri: value,
      media_type: String(fallbackType || "track").toLowerCase(),
      provider: "",
      item_id: "",
      media_id: value,
    };
    if (!value.includes("://")) return fallback;
    const [providerRaw, restRaw] = value.split("://");
    const provider = String(providerRaw || "").trim();
    const rest = String(restRaw || "").replace(/^\/+/, "");
    const segments = rest.split("/").filter(Boolean);
    if (!segments.length) return { ...fallback, provider };
    const mediaType = String(segments[0] || fallback.media_type).toLowerCase();
    const itemId = segments.slice(1).join("/") || rest;
    return {
      uri: value,
      provider,
      media_type: mediaType || fallback.media_type,
      item_id: itemId,
      media_id: itemId || value,
    };
  },
  mediaRefsEquivalent(uriA = "", uriB = "", fallbackType = "track") {
    const left = String(uriA || "").trim();
    const right = String(uriB || "").trim();
    if (!left || !right) return false;
    if (left === right) return true;
    const leftRef = HomeiiMediaQueueFoundation.parseMediaReference(left, fallbackType);
    const rightRef = HomeiiMediaQueueFoundation.parseMediaReference(right, fallbackType);
    return !!(
      leftRef.provider
      && rightRef.provider
      && leftRef.provider === rightRef.provider
      && leftRef.media_type === rightRef.media_type
      && leftRef.item_id
      && leftRef.item_id === rightRef.item_id
    );
  },
  getQueueItemKey(item) {
    const stableId = HomeiiMediaQueueFoundation.getQueueItemStableId(item);
    const sortIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(item?.sort_index);
    return String(stableId || (Number.isFinite(sortIndex) ? sortIndex : "") || HomeiiMediaQueueFoundation.getQueueItemUri(item) || "");
  },
  getQueueItemStableId(item) {
    const uri = String(HomeiiMediaQueueFoundation.getQueueItemUri(item) || "").trim();
    const parsed = HomeiiMediaQueueFoundation.parseMediaReference(uri, item?.media_item?.media_type || item?.media_type || "track");
    const trustedQueueId = [item?.queue_service_id]
      .map((value) => String(value || "").trim())
      .find(Boolean);
    if (trustedQueueId) return trustedQueueId;
    const queueItemId = String(item?.queue_item_id || "").trim();
    if (queueItemId && item?.queue_item_id_trusted !== false) return queueItemId;
    const fallbackCandidates = [item?.item_id, item?.id]
      .map((value) => String(value || "").trim())
      .filter(Boolean);
    return fallbackCandidates.find((value) =>
      value !== uri
      && value !== parsed.item_id
      && !uri.endsWith(`/${value}`)
      && !uri.endsWith(`:${value}`)
    ) || "";
  },
  getQueueItemPlaybackId(item) {
    const value = HomeiiMediaQueueFoundation.getQueueItemStableId(item);
    if (!value || /^\d+$/.test(value)) return "";
    return value;
  },
  getQueueItemUri(item) {
    return item?.media_item?.uri || item?.uri || item?.streamdetails?.uri || "";
  },
  queueItemPrimaryArtist(item = {}) {
    return item?.media_artist
      || item?.artist
      || item?.media_item?.artist
      || (Array.isArray(item?.media_item?.artists) ? item.media_item.artists.map((artist) => artist?.name).filter(Boolean).join(", ") : "")
      || "";
  },
  queueItemPrimaryTitle(item = {}) {
    return item?.media_item?.name || item?.media_title || item?.name || "";
  },
  queueItemMatchTitle(item = {}) {
    return HomeiiMediaQueueFoundation.normalizeComparableText(item?.media_item?.name || item?.media_title || item?.name || "");
  },
  queueItemMatchArtist(item = {}) {
    return HomeiiMediaQueueFoundation.normalizeComparableText(
      item?.media_artist
        || (item?.media_item?.artists || []).map((artist) => artist?.name).filter(Boolean).join(", ")
        || "",
    );
  },
  queueTitleArtistMatch(item, title = "", artist = "") {
    const normalizedTitle = HomeiiMediaQueueFoundation.normalizeComparableText(title);
    if (!item || !normalizedTitle) return false;
    const itemTitle = HomeiiMediaQueueFoundation.queueItemMatchTitle(item);
    const itemArtist = HomeiiMediaQueueFoundation.queueItemMatchArtist(item);
    const normalizedArtist = HomeiiMediaQueueFoundation.normalizeComparableText(artist);
    return itemTitle === normalizedTitle && (
      !normalizedArtist
      || itemArtist.includes(normalizedArtist)
      || normalizedArtist.includes(itemArtist)
    );
  },
  findQueueItemIndex(queueItems = [], {
    queueItemId = "",
    uri = "",
    sortIndex = "",
    fallbackType = "track",
  } = {}, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    const items = Array.isArray(queueItems) ? queueItems : [];
    const normalizedIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(sortIndex);
    const key = String(queueItemId || "").trim();
    const targetUri = String(uri || "").trim();
    const keyIndex = key ? items.findIndex((item) =>
      HomeiiMediaQueueFoundation.getQueueItemStableId(item) === key
      || HomeiiMediaQueueFoundation.getQueueItemKey(item) === key
    ) : -1;
    if (keyIndex >= 0) return keyIndex;
    const uriIndex = targetUri ? items.findIndex((item) =>
      compareMediaRefs(
        HomeiiMediaQueueFoundation.getQueueItemUri(item),
        targetUri,
        item?.media_item?.media_type || item?.media_type || fallbackType,
      )
    ) : -1;
    if (uriIndex >= 0) return uriIndex;
    return items.findIndex((item) => Number.isFinite(normalizedIndex) && Number(item?.sort_index) === normalizedIndex);
  },
  mobileCurrentQueueIndex(value) {
    const currentIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(value);
    return Number.isFinite(currentIndex) ? currentIndex : -1;
  },
  sortQueueItems(items = []) {
    return [...(Array.isArray(items) ? items : [])]
      .filter(Boolean)
      .sort((a, b) => Number(a?.sort_index ?? 0) - Number(b?.sort_index ?? 0));
  },
  queueItemsContainCurrent(items = [], queueState = null) {
    if (!Array.isArray(items) || !items.length || !queueState) return false;
    const currentIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(queueState.current_index);
    const currentKey = HomeiiMediaQueueFoundation.getQueueItemKey(queueState.current_item);
    return items.some((item) =>
      (Number.isFinite(currentIndex) && Number(item?.sort_index) === currentIndex)
      || (currentKey && HomeiiMediaQueueFoundation.getQueueItemKey(item) === currentKey)
    );
  },
  queueItemMatchesPlayer(item, player, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    if (!item || !player) return false;
    const playerUri = String(player?.attributes?.media_content_id || "").trim();
    const itemUri = String(HomeiiMediaQueueFoundation.getQueueItemUri(item) || "").trim();
    if (playerUri && itemUri) {
      return compareMediaRefs(playerUri, itemUri, item?.media_item?.media_type || item?.media_type || "track");
    }
    const playerTitle = HomeiiMediaQueueFoundation.normalizeComparableText(player?.attributes?.media_title || "");
    if (!playerTitle) return false;
    const playerArtist = HomeiiMediaQueueFoundation.normalizeComparableText(player?.attributes?.media_artist || "");
    return HomeiiMediaQueueFoundation.queueTitleArtistMatch(item, playerTitle, playerArtist);
  },
  resolveMobileUpNextItem(queueState = {}, queueItems = []) {
    if (queueState?.next_item) return queueState.next_item;
    const items = Array.isArray(queueItems) ? queueItems : [];
    if (!items.length) return null;
    const currentIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(queueState.current_index);
    if (Number.isFinite(currentIndex)) {
      return items.find((item) => Number(item?.sort_index) === currentIndex + 1)
        || items.find((item) => Number(item?.sort_index) > currentIndex)
        || null;
    }
    const currentKey = HomeiiMediaQueueFoundation.getQueueItemKey(queueState.current_item);
    if (currentKey) {
      const index = items.findIndex((item) => HomeiiMediaQueueFoundation.getQueueItemKey(item) === currentKey);
      if (index >= 0 && index < items.length - 1) return items[index + 1];
    }
    return items[1] || null;
  },
  entryTargetsCurrentMedia(entry = {}, current = {}, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    const currentUri = String(current?.uri || "").trim();
    const entryUri = String(entry?.uri || "").trim();
    if (currentUri && entryUri) {
      return compareMediaRefs(currentUri, entryUri, entry?.media_type || current?.media_type || "track");
    }
    const currentTitle = HomeiiMediaQueueFoundation.normalizeComparableText(current?.name || "");
    const entryTitle = HomeiiMediaQueueFoundation.normalizeComparableText(entry?.name || entry?.title || "");
    if (!currentTitle || !entryTitle || currentTitle !== entryTitle) return false;
    const currentArtist = HomeiiMediaQueueFoundation.normalizeComparableText(current?.artist || "");
    const entryArtist = HomeiiMediaQueueFoundation.normalizeComparableText(entry?.artist || "");
    return !currentArtist
      || !entryArtist
      || currentArtist === entryArtist
      || currentArtist.includes(entryArtist)
      || entryArtist.includes(currentArtist);
  },
  resolveQueuePlayIndex(queueItems = [], {
    queueItemId = "",
    fallbackUri = "",
    explicitSortIndex = "",
  } = {}, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    const normalizedExplicit = HomeiiMediaQueueFoundation.normalizeFiniteNumber(explicitSortIndex);
    const items = Array.isArray(queueItems) ? queueItems : [];
    const key = String(queueItemId || "").trim();
    const uri = String(fallbackUri || "").trim();
    const match = (key ? items.find((item) =>
      HomeiiMediaQueueFoundation.getQueueItemStableId(item) === key
      || HomeiiMediaQueueFoundation.getQueueItemKey(item) === key
    ) : null)
      || (uri ? items.find((item) =>
        compareMediaRefs(
          HomeiiMediaQueueFoundation.getQueueItemUri(item),
          uri,
          item?.media_item?.media_type || item?.media_type || "track",
        )
      ) : null);
    const resolved = Number(match?.sort_index);
    if (Number.isFinite(resolved)) return resolved;
    return Number.isFinite(normalizedExplicit) ? normalizedExplicit : null;
  },
  getQueueItemByIndexOrKey(queueItems = [], {
    sortIndex = "",
    queueItemId = "",
    fallbackUri = "",
  } = {}, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    const normalizedIndex = HomeiiMediaQueueFoundation.normalizeFiniteNumber(sortIndex);
    const key = String(queueItemId || "").trim();
    const uri = String(fallbackUri || "").trim();
    const items = Array.isArray(queueItems) ? queueItems : [];
    return (key ? items.find((item) =>
      HomeiiMediaQueueFoundation.getQueueItemStableId(item) === key
      || HomeiiMediaQueueFoundation.getQueueItemKey(item) === key
    ) : null)
      || (uri ? items.find((item) =>
        compareMediaRefs(
          HomeiiMediaQueueFoundation.getQueueItemUri(item),
          uri,
          item?.media_item?.media_type || item?.media_type || "track",
        )
      ) : null)
      || items.find((item) => Number.isFinite(normalizedIndex) && Number(item?.sort_index) === normalizedIndex)
      || null;
  },
  resolveMobileArtStackContext({
    queueItems = [],
    currentIndexValue = "",
    player = null,
    currentItem = null,
    hasPendingPlay = false,
    pendingKey = "",
    pendingUri = "",
    pendingIndexValue = "",
    browseOffset = 0,
  } = {}, compareMediaRefs = HomeiiMediaQueueFoundation.mediaRefsEquivalent) {
    const sortedQueueItems = HomeiiMediaQueueFoundation.sortQueueItems(queueItems);
    const currentIndex = HomeiiMediaQueueFoundation.mobileCurrentQueueIndex(currentIndexValue);
    const playerUri = String(player?.attributes?.media_content_id || "").trim();
    const currentItemTitle = currentItem?.media_item?.name || currentItem?.media_title || currentItem?.name || "";
    const currentItemArtist = currentItem?.media_artist || (currentItem?.media_item?.artists || []).map((artist) => artist?.name).filter(Boolean).join(", ") || "";
    const playerTitle = HomeiiMediaQueueFoundation.normalizeComparableText(
      hasPendingPlay
        ? (currentItemTitle || player?.attributes?.media_title || "")
        : (player?.attributes?.media_title || currentItemTitle || ""),
    );
    const playerArtist = HomeiiMediaQueueFoundation.normalizeComparableText(
      hasPendingPlay
        ? (currentItemArtist || player?.attributes?.media_artist || "")
        : (player?.attributes?.media_artist || currentItemArtist || ""),
    );
    let baseIndex = -1;
    const titleMatches = (item) => HomeiiMediaQueueFoundation.queueTitleArtistMatch(item, playerTitle, playerArtist);
    if (hasPendingPlay) {
      const pendingMatch = HomeiiMediaQueueFoundation.findQueueItemIndex(sortedQueueItems, {
        queueItemId: pendingKey,
        uri: pendingUri,
        sortIndex: pendingIndexValue,
      }, compareMediaRefs);
      if (pendingMatch >= 0) baseIndex = pendingMatch;
    }
    if (currentItem) {
      const currentKey = HomeiiMediaQueueFoundation.getQueueItemKey(currentItem);
      const currentUri = HomeiiMediaQueueFoundation.getQueueItemUri(currentItem);
      const keyIndex = HomeiiMediaQueueFoundation.findQueueItemIndex(sortedQueueItems, {
        queueItemId: currentKey,
        uri: currentUri,
      }, compareMediaRefs);
      if (keyIndex >= 0 && (hasPendingPlay || !playerTitle || titleMatches(sortedQueueItems[keyIndex]))) {
        baseIndex = keyIndex;
      }
    }
    if (baseIndex < 0 && playerUri) {
      baseIndex = HomeiiMediaQueueFoundation.findQueueItemIndex(sortedQueueItems, { uri: playerUri }, compareMediaRefs);
    }
    if (baseIndex < 0 && !playerUri && playerTitle) {
      baseIndex = sortedQueueItems.findIndex((item) => titleMatches(item));
    }
    if (baseIndex < 0 && Number.isFinite(currentIndex)) {
      baseIndex = sortedQueueItems.findIndex((item) => Number(item?.sort_index) === currentIndex);
    }
    if (baseIndex < 0 && Number.isFinite(currentIndex) && currentIndex >= 0 && currentIndex < sortedQueueItems.length) {
      baseIndex = currentIndex;
    }
    if (baseIndex < 0) baseIndex = 0;
    const minOffset = sortedQueueItems.length ? -baseIndex : 0;
    const maxOffset = sortedQueueItems.length ? (sortedQueueItems.length - 1 - baseIndex) : 0;
    const offset = Math.max(minOffset, Math.min(maxOffset, Number(browseOffset || 0)));
    const displayIndex = Math.max(0, Math.min(sortedQueueItems.length - 1, baseIndex + offset));
    return {
      queueItems: sortedQueueItems,
      baseIndex,
      displayIndex,
      offset,
    };
  },
});

const HomeiiFavoritesFoundation = Object.freeze({
  buildCurrentMediaLikeMeta({
    player = null,
    queueItem = {},
    resolvedUri = "",
    queueItemImage = "",
    fallbackName = "Unknown",
  } = {}, parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference) {
    const media = queueItem?.media_item || {};
    const playerUri = String(player?.attributes?.media_content_id || "").trim();
    const uri = playerUri || String(resolvedUri || "").trim();
    const artist = Array.isArray(media?.artists)
      ? media.artists.map((artistEntry) => artistEntry?.name).filter(Boolean).join(", ")
      : (player?.attributes?.media_artist || "");
    const parsed = parseMediaReferenceFn(
      uri,
      media?.media_type || queueItem?.media_type || player?.attributes?.media_content_type || "track",
    );
    return {
      uri,
      ...parsed,
      media_type: parsed.media_type || media?.media_type || queueItem?.media_type || "track",
      name: player?.attributes?.media_title || media?.name || uri || fallbackName,
      artist: artist || "",
      album: media?.album?.name || player?.attributes?.media_album_name || "",
      image: queueItemImage || media?.image || media?.album?.image || player?.attributes?.entity_picture_local || player?.attributes?.entity_picture || "",
    };
  },
  favoriteEntryArtist(entry = {}) {
    return String(
      entry?.artist
        || entry?.artists?.map?.((artist) => artist?.name).filter(Boolean).join(", ")
        || entry?.media_item?.artists?.map?.((artist) => artist?.name).filter(Boolean).join(", ")
        || entry?.media_artist
        || "",
    ).trim();
  },
  favoriteEntryTitle(entry = {}) {
    return String(entry?.name || entry?.title || entry?.media_item?.name || "").trim();
  },
  normalizeComparableText(value = "") {
    return String(value || "").trim().toLowerCase();
  },
  favoriteRemoveArgsFromItem(item = {}, fallbackType = "track", parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference) {
    if (!item || typeof item !== "object") return null;
    const mediaType = String(item.media_type || item.type || item.media_item?.media_type || fallbackType || "track").toLowerCase();
    const parsed = parseMediaReferenceFn(item.uri || item.media_item?.uri || "", mediaType);
    const explicitLibraryId = item.library_item_id
      || (String(item.provider || item.provider_domain || item.provider_instance || "").toLowerCase() === "library"
        ? (item.item_id || item.id || "")
        : "");
    const libraryItemId = String(parsed.provider === "library" ? parsed.item_id : explicitLibraryId || "").trim();
    if (!libraryItemId) return null;
    return { media_type: parsed.media_type || mediaType, library_item_id: libraryItemId };
  },
  findFavoriteEntryMatch(entry = {}, likedItems = [], {
    parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference,
  } = {}) {
    if (!Array.isArray(likedItems) || !likedItems.length) return null;
    const targetUri = String(entry?.uri || "").trim();
    const targetType = String(entry?.media_type || entry?.type || "track").toLowerCase();
    const targetLibraryId = String(entry?.library_item_id || "").trim();
    const targetItemId = String(entry?.item_id || entry?.id || "").trim();
    const targetProvider = String(entry?.provider || entry?.provider_domain || entry?.provider_instance || "").trim().toLowerCase();
    const targetTitle = HomeiiFavoritesFoundation.normalizeComparableText(HomeiiFavoritesFoundation.favoriteEntryTitle(entry));
    const targetArtist = HomeiiFavoritesFoundation.normalizeComparableText(HomeiiFavoritesFoundation.favoriteEntryArtist(entry));
    for (const item of likedItems) {
      const candidateLibraryId = String(item?.library_item_id || "").trim();
      const candidateItemId = String(item?.item_id || item?.id || "").trim();
      const candidateProvider = String(item?.provider || item?.provider_domain || item?.provider_instance || "").trim().toLowerCase();
      const candidateUri = String(item?.uri || "").trim();
      const candidateType = String(item?.media_type || item?.type || "").toLowerCase();
      if (targetLibraryId && candidateLibraryId && targetLibraryId === candidateLibraryId) return item;
      if (targetItemId && candidateItemId && targetProvider && candidateProvider && targetItemId === candidateItemId && targetProvider === candidateProvider) {
        return item;
      }
      if (candidateUri && targetUri && candidateUri === targetUri) return item;
      const parsedTarget = parseMediaReferenceFn(targetUri, targetType || "track");
      const parsedCandidate = parseMediaReferenceFn(candidateUri, candidateType || targetType || "track");
      if (parsedTarget.provider && parsedCandidate.provider && parsedTarget.provider === parsedCandidate.provider && parsedTarget.item_id && parsedTarget.item_id === parsedCandidate.item_id) {
        return item;
      }
      const candidateTitle = HomeiiFavoritesFoundation.normalizeComparableText(HomeiiFavoritesFoundation.favoriteEntryTitle(item));
      const candidateArtist = HomeiiFavoritesFoundation.normalizeComparableText(HomeiiFavoritesFoundation.favoriteEntryArtist(item));
      if (targetTitle && candidateTitle === targetTitle && (!targetArtist || !candidateArtist || candidateArtist === targetArtist || candidateArtist.includes(targetArtist) || targetArtist.includes(candidateArtist))) {
        return item;
      }
    }
    return null;
  },
  matchFavoriteLibraryItem(entry = {}, likedItems = [], fallbackType = "", {
    parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference,
    favoriteRemoveArgsFromItemFn = HomeiiFavoritesFoundation.favoriteRemoveArgsFromItem,
    findFavoriteEntryMatchFn = HomeiiFavoritesFoundation.findFavoriteEntryMatch,
  } = {}) {
    const effectiveFallbackType = fallbackType || entry?.media_type || entry?.type || "track";
    const match = findFavoriteEntryMatchFn(entry, likedItems, { parseMediaReferenceFn });
    return match ? favoriteRemoveArgsFromItemFn(match, effectiveFallbackType, parseMediaReferenceFn) : null;
  },
  buildOptimisticFavoriteEntry(entry = {}, liked = false) {
    return {
      uri: String(entry?.uri || "").trim(),
      media_type: entry?.media_type || entry?.type || "track",
      item_id: entry?.item_id || "",
      provider: entry?.provider || "",
      library_item_id: entry?.library_item_id || "",
      name: entry?.name || entry?.title || entry?.media_item?.name || "",
      artist: HomeiiFavoritesFoundation.favoriteEntryArtist(entry),
      album: entry?.album || entry?.media_item?.album?.name || "",
      image: entry?.image || entry?.media_item?.image || entry?.media_item?.album?.image || "",
      favorite: !!liked,
    };
  },
  applyOptimisticFavoriteCache(likedItems = [], nextEntry = {}, liked = false, {
    compareMediaRefsFn = HomeiiMediaQueueFoundation.mediaRefsEquivalent,
    matchFavoriteLibraryItemFn = HomeiiFavoritesFoundation.matchFavoriteLibraryItem,
  } = {}) {
    const items = Array.isArray(likedItems) ? [...likedItems] : [];
    const idx = items.findIndex((item) =>
      compareMediaRefsFn(String(item?.uri || "").trim(), nextEntry.uri, item?.media_type || nextEntry.media_type || "track")
      || !!matchFavoriteLibraryItemFn(nextEntry, [item], nextEntry.media_type || "track")
    );
    if (liked) {
      if (idx >= 0) items[idx] = { ...items[idx], ...nextEntry, favorite: true };
      else items.unshift(nextEntry);
    } else if (idx >= 0) {
      items.splice(idx, 1);
    }
    return items;
  },
  isEntryLiked(entry = {}, {
    useMaLikedMode = false,
    likedItems = null,
    localLikedUris = null,
  } = {}, {
    compareMediaRefsFn = HomeiiMediaQueueFoundation.mediaRefsEquivalent,
    matchFavoriteLibraryItemFn = HomeiiFavoritesFoundation.matchFavoriteLibraryItem,
  } = {}) {
    const uri = String(entry?.uri || "").trim();
    if (useMaLikedMode) {
      if (Array.isArray(likedItems)) {
        return uri
          ? likedItems.some((item) => compareMediaRefsFn(String(item?.uri || "").trim(), uri, item?.media_type || entry?.media_type || "track"))
            || !!matchFavoriteLibraryItemFn(entry, likedItems, entry?.media_type || entry?.type || "track")
          : !!matchFavoriteLibraryItemFn(entry, likedItems, entry?.media_type || entry?.type || "track");
      }
      return !!entry?.favorite || !!entry?.media_item?.favorite;
    }
    if (entry?.favorite || entry?.media_item?.favorite) return true;
    if (!uri) return false;
    if (localLikedUris instanceof Set) return localLikedUris.has(uri);
    if (Array.isArray(localLikedUris)) return localLikedUris.includes(uri);
    return false;
  },
  resolveCurrentMediaFavoriteState({
    currentUri = "",
    override = null,
    queueItem = {},
    currentEntry = null,
    useMaLikedMode = false,
    likedItems = null,
    localLikedUris = null,
    now = Date.now(),
  } = {}, {
    compareMediaRefsFn = HomeiiMediaQueueFoundation.mediaRefsEquivalent,
    matchFavoriteLibraryItemFn = HomeiiFavoritesFoundation.matchFavoriteLibraryItem,
  } = {}) {
    const uri = String(currentUri || "").trim();
    if (!uri) return false;
    if (override?.uri === uri && Number(now || 0) - Number(override?.ts || 0) < 8000) {
      return !!override.liked;
    }
    const queueFavorite = queueItem?.media_item?.favorite;
    if (typeof queueFavorite === "boolean") return queueFavorite;
    if (typeof queueItem?.favorite === "boolean") return queueItem.favorite;
    if (useMaLikedMode) {
      if (Array.isArray(likedItems)) {
        return likedItems.some((item) => compareMediaRefsFn(String(item?.uri || "").trim(), uri, item?.media_type || "track"))
          || !!matchFavoriteLibraryItemFn(currentEntry || {}, likedItems, currentEntry?.media_type || "track");
      }
      return false;
    }
    if (localLikedUris instanceof Set) return localLikedUris.has(uri);
    if (Array.isArray(localLikedUris)) return localLikedUris.includes(uri);
    return false;
  },
  resolveCachedFavoriteRemoveArgs({
    entry = {},
    mediaType = "track",
    likedItems = [],
    currentEntry = null,
    currentEntryMatches = false,
  } = {}, {
    parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference,
    favoriteRemoveArgsFromItemFn = HomeiiFavoritesFoundation.favoriteRemoveArgsFromItem,
    findFavoriteEntryMatchFn = HomeiiFavoritesFoundation.findFavoriteEntryMatch,
    matchFavoriteLibraryItemFn = HomeiiFavoritesFoundation.matchFavoriteLibraryItem,
  } = {}) {
    const uri = String(entry?.uri || "").trim();
    const ref = parseMediaReferenceFn(uri, mediaType);
    if (ref.provider === "library" && ref.item_id) {
      return { media_type: ref.media_type || mediaType, library_item_id: ref.item_id };
    }
    const canonicalEntry = findFavoriteEntryMatchFn(entry, likedItems, { parseMediaReferenceFn });
    if (canonicalEntry) {
      const canonicalArgs = favoriteRemoveArgsFromItemFn(canonicalEntry, mediaType, parseMediaReferenceFn);
      if (canonicalArgs) return canonicalArgs;
    }
    const resolvedFromCache = matchFavoriteLibraryItemFn(entry, likedItems, mediaType, {
      parseMediaReferenceFn,
      favoriteRemoveArgsFromItemFn,
      findFavoriteEntryMatchFn,
    });
    if (resolvedFromCache) return resolvedFromCache;
    if (currentEntryMatches && currentEntry?.uri && currentEntry.uri !== uri) {
      return matchFavoriteLibraryItemFn(currentEntry, likedItems, mediaType, {
        parseMediaReferenceFn,
        favoriteRemoveArgsFromItemFn,
        findFavoriteEntryMatchFn,
      });
    }
    return null;
  },
});

const HomeiiPlayersFoundation = Object.freeze({
  genericPlayerTokens: new Set([
    "media",
    "player",
    "speaker",
    "room",
    "homeii",
    "browser",
    "music",
    "assistant",
    "רמקולים",
    "נגן",
  ]),
  entityMatchTokens(value = "") {
    return String(value || "")
      .toLowerCase()
      .replace(/^media_player\./, "")
      .replace(/^button\./, "")
      .replace(/[_\-.]+/g, " ")
      .split(/\s+/)
      .map((token) => token.trim())
      .filter((token) => token && token.length > 1);
  },
  isLikelyBrowserPlayer(player = null) {
    if (!player) return false;
    const attrs = player.attributes || {};
    const haystack = [
      player.entity_id,
      attrs.friendly_name,
      attrs.mass_player_type,
      attrs.mass_player_id,
      attrs.app_id,
      attrs.provider,
      attrs.provider_name,
      attrs.source,
      attrs.model,
    ].filter(Boolean).join(" ").toLowerCase();
    return haystack.includes("sendspin")
      || haystack.includes("browser")
      || haystack.includes("web player")
      || haystack.includes("this device");
  },
  isMusicAssistantPlayer(player = null) {
    if (!player?.entity_id?.startsWith("media_player.")) return false;
    const attrs = player.attributes || {};
    const identity = [
      attrs.app_id,
      attrs.integration,
      attrs.platform,
      attrs.provider,
      attrs.provider_name,
    ].filter(Boolean).join(" ").toLowerCase();
    return identity.includes("music_assistant")
      || identity.includes("music assistant")
      || !!attrs.mass_player_type
      || !!attrs.mass_player_id
      || !!attrs.active_queue;
  },
  getBrowserPlayers(players = []) {
    return (Array.isArray(players) ? players : []).filter((player) => HomeiiPlayersFoundation.isLikelyBrowserPlayer(player));
  },
  getThisDevicePlayer(players = [], rememberedId = "") {
    const target = String(rememberedId || "").trim();
    if (!target) return null;
    return (Array.isArray(players) ? players : []).find((player) => player?.entity_id === target) || null;
  },
  resolvePinnedPlayerEntities(preferredIds = [], players = []) {
    const validIds = new Set((Array.isArray(players) ? players : []).map((player) => String(player?.entity_id || "").toLowerCase()));
    return (Array.isArray(preferredIds) ? preferredIds : [])
      .filter((entityId) => validIds.has(String(entityId || "").toLowerCase()));
  },
  playerByEntityId(entityId = "", players = [], hassStates = {}) {
    const target = String(entityId || "").trim();
    if (!target) return null;
    return (Array.isArray(players) ? players : []).find((player) => player?.entity_id === target)
      || hassStates?.[target]
      || null;
  },
  favoriteButtonEntityForPlayer({
    player = null,
    hassStates = {},
    explicitEntity = "",
    fallbackEntity = "button.bathroom_favorite_current_song_2",
  } = {}) {
    const configured = String(explicitEntity || "").trim();
    if (configured && hassStates?.[configured]) return configured;
    if (hassStates?.[fallbackEntity]) {
      const selectedName = `${player?.entity_id || ""} ${player?.attributes?.friendly_name || ""}`.toLowerCase();
      if (!selectedName || selectedName.includes("bathroom") || selectedName.includes("מקלחת")) {
        return fallbackEntity;
      }
    }
    const buttons = Object.values(hassStates || {}).filter((entity) => {
      if (!entity?.entity_id?.startsWith("button.")) return false;
      const search = `${entity.entity_id} ${entity.attributes?.friendly_name || ""}`.toLowerCase();
      return search.includes("favorite") || search.includes("אהוב") || search.includes("אהבתי");
    });
    if (!buttons.length) return "";
    if (buttons.length === 1) return buttons[0]?.entity_id || "";
    const tokens = [
      ...HomeiiPlayersFoundation.entityMatchTokens(player?.entity_id || ""),
      ...HomeiiPlayersFoundation.entityMatchTokens(player?.attributes?.friendly_name || ""),
    ].filter((token) => !HomeiiPlayersFoundation.genericPlayerTokens.has(token));
    const scored = buttons
      .map((entity) => {
        const haystack = `${entity.entity_id} ${entity.attributes?.friendly_name || ""}`.toLowerCase();
        const score = tokens.reduce((sum, token) => sum + (haystack.includes(token) ? 1 : 0), 0);
        const currentSongBoost = /(current|song|track|playing|נוכחי|מתנגן)/.test(haystack) ? 0.5 : 0;
        return { entity_id: entity.entity_id, score: score + currentSongBoost };
      })
      .sort((left, right) => right.score - left.score);
    if (scored[0]?.score > 0) return scored[0].entity_id;
    const genericCurrent = buttons.find((entity) => /(current|song|track|playing|נוכחי|מתנגן)/.test(`${entity.entity_id} ${entity.attributes?.friendly_name || ""}`.toLowerCase()));
    if (genericCurrent?.entity_id) return genericCurrent.entity_id;
    return "";
  },
  favoriteButtonDeviceId(entityId = "", hassEntities = {}) {
    const target = String(entityId || "").trim();
    if (!target) return "";
    return String(hassEntities?.[target]?.device_id || "").trim();
  },
  announcementEligiblePlayers(players = []) {
    return (Array.isArray(players) ? players : [])
      .filter((player) => player?.entity_id)
      .filter((player) => !HomeiiPlayersFoundation.isLikelyBrowserPlayer(player));
  },
  mobileNavigableActivePlayers(players = [], pinnedEntityIds = [], isPlayerActiveFn = () => false) {
    const sourcePlayers = Array.isArray(players) ? players : [];
    const preferred = Array.isArray(pinnedEntityIds) ? pinnedEntityIds.filter(Boolean) : [];
    if (preferred.length) {
      return preferred
        .map((entityId) => sourcePlayers.find((player) => player?.entity_id === entityId))
        .filter(Boolean);
    }
    return sourcePlayers
      .filter((player) => isPlayerActiveFn(player))
      .filter((player) => !HomeiiPlayersFoundation.isLikelyBrowserPlayer(player));
  },
  playerGroupMemberIds(player = null) {
    const ids = Array.isArray(player?.attributes?.group_members)
      ? player.attributes.group_members.filter(Boolean)
      : [];
    if (player?.entity_id && ids.length && !ids.includes(player.entity_id)) ids.unshift(player.entity_id);
    return [...new Set(ids)];
  },
  isStaticGroupPlayer(player = null) {
    if (!player) return false;
    const attrs = player.attributes || {};
    const typeText = [
      player.entity_id,
      attrs.friendly_name,
      attrs.mass_player_type,
      attrs.player_type,
      attrs.type,
      attrs.grouping_type,
      attrs.group_type,
      attrs.device_class,
    ].map((value) => String(value || "").toLowerCase()).join(" ");
    const looksLikeGroup = !!(attrs.is_group || attrs.is_group_player || attrs.group_childs || attrs.group_children || attrs.group_members?.length > 1);
    return looksLikeGroup && /(sync|static|group|party|all speakers|whole home|everywhere)/.test(typeText);
  },
  playerGroupCount(player = null) {
    if (HomeiiPlayersFoundation.isStaticGroupPlayer(player)) return 0;
    const count = HomeiiPlayersFoundation.playerGroupMemberIds(player).length;
    return count > 1 ? count : 0;
  },
  playerGroupMemberNames(player = null, players = []) {
    const ids = HomeiiPlayersFoundation.playerGroupMemberIds(player);
    const byId = new Map((Array.isArray(players) ? players : []).map((entry) => [entry?.entity_id, entry]));
    return ids
      .map((entityId) => byId.get(entityId)?.attributes?.friendly_name || entityId)
      .filter(Boolean);
  },
  groupAverageVolume(player = null, players = []) {
    const ids = HomeiiPlayersFoundation.playerGroupMemberIds(player);
    const byId = new Map((Array.isArray(players) ? players : []).map((entry) => [entry?.entity_id, entry]));
    const volumes = ids
      .map((entityId) => byId.get(entityId)?.attributes?.volume_level)
      .map((value) => Number(value))
      .filter((value) => Number.isFinite(value));
    if (!volumes.length) return Math.round((player?.attributes?.volume_level || 0) * 100);
    return Math.round((volumes.reduce((sum, value) => sum + value, 0) / volumes.length) * 100);
  },
  groupedPlayerIds(players = []) {
    const sourcePlayers = Array.isArray(players) ? players : [];
    const ids = new Set();
    const byId = new Map(sourcePlayers.map((player) => [player?.entity_id, player]));
    for (const player of sourcePlayers) {
      if (HomeiiPlayersFoundation.isLikelyBrowserPlayer(player)) continue;
      if (HomeiiPlayersFoundation.isStaticGroupPlayer(player)) continue;
      const members = HomeiiPlayersFoundation.playerGroupMemberIds(player);
      if (members.length > 1) {
        members
          .filter((entityId) => entityId && entityId !== player.entity_id)
          .filter((entityId) => !HomeiiPlayersFoundation.isLikelyBrowserPlayer(byId.get(entityId)))
          .filter((entityId) => !HomeiiPlayersFoundation.isStaticGroupPlayer(byId.get(entityId)))
          .forEach((entityId) => ids.add(entityId));
      }
    }
    return Array.from(ids);
  },
});

const HomeiiMediaPresentationFoundation = Object.freeze({
  buildCurrentTrackInfo({
    player = null,
    queueItem = null,
  } = {}) {
    const currentQueueItem = queueItem || null;
    const media = currentQueueItem?.media_item || {};
    const title = media?.name || player?.attributes?.media_title || "";
    const artists = Array.isArray(media?.artists) ? media.artists.map((artist) => artist?.name).filter(Boolean).join(", ") : "";
    const artist = artists || player?.attributes?.media_artist || "";
    const album = media?.album?.name || player?.attributes?.media_album_name || "";
    const duration = Number(currentQueueItem?.duration || player?.attributes?.media_duration || 0);
    const key = [title, artist, album].map((part) => String(part || "").trim().toLowerCase()).join("|");
    return { title, artist, album, duration, key };
  },
  sourceProviderMeta(value = "", { libraryLabel = "Library", radioLabel = "Radio" } = {}) {
    const raw = String(value || "").trim();
    const normalized = raw.toLowerCase();
    if (!normalized) return null;
    if (/(spotify)/.test(normalized)) return { key: "spotify", label: "Spotify" };
    if (/(tidal)/.test(normalized)) return { key: "tidal", label: "TIDAL" };
    if (/(youtube|ytmusic)/.test(normalized)) return { key: "youtube", label: "YouTube Music" };
    if (/(apple)/.test(normalized)) return { key: "apple", label: "Apple Music" };
    if (/(qobuz)/.test(normalized)) return { key: "qobuz", label: "Qobuz" };
    if (/(deezer)/.test(normalized)) return { key: "deezer", label: "Deezer" };
    if (/(filesystem|local|library|file)/.test(normalized)) return { key: "library", label: libraryLabel };
    if (/(radio_browser|radiobrowser|tunein|radio)/.test(normalized)) return { key: "radio", label: radioLabel };
    return { key: normalized.replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 24) || "source", label: raw };
  },
  qualityBadgeLabel(values = []) {
    const haystack = (Array.isArray(values) ? values : [values])
      .flatMap((value) => Array.isArray(value) ? value : [value])
      .map((value) => {
        if (typeof value !== "object" || value === null) return String(value || "");
        try {
          return JSON.stringify(value);
        } catch (_) {
          return String(value || "");
        }
      })
      .join(" | ")
      .toLowerCase();
    if (!haystack) return "";
    if (/(hi[\s-]?res|24[\s-]?bit|88\.2|96[\s-]?khz|96000|176\.4|192[\s-]?khz|192000)/.test(haystack)) return "Hi-Res";
    if (/(lossless|flac|alac|wav|aiff|pcm)/.test(haystack)) return "Lossless";
    return "";
  },
  stripLyricsTimestamps(text = "") {
    return String(text || "")
      .replace(/\r/g, "")
      .replace(/^\[[a-z]+:[^\]]*\]\s*$/gim, "")
      .replace(/\[\d{1,3}:\d{2}(?:[.:]\d{1,3})?\]\s*/g, "")
      .trim();
  },
  coerceLyricsRawText(value) {
    if (!value) return "";
    if (typeof value === "string") return String(value || "").replace(/\r/g, "").trim();
    if (typeof value === "object") {
      return String(
        value.syncedLyrics
        || value.synced_lyrics
        || value.plainLyrics
        || value.plain_lyrics
        || value.lyrics
        || value.text
        || "",
      ).replace(/\r/g, "").trim();
    }
    return "";
  },
  coerceLyricsText(value) {
    return HomeiiMediaPresentationFoundation.stripLyricsTimestamps(
      HomeiiMediaPresentationFoundation.coerceLyricsRawText(value),
    );
  },
  parseLrcLyrics(text = "") {
    const rows = [];
    const raw = String(text || "").replace(/\r/g, "");
    const timeTag = /\[(\d{1,3}):(\d{2})(?:[.:](\d{1,3}))?\]/g;
    raw.split("\n").forEach((line) => {
      const tags = [...line.matchAll(timeTag)];
      if (!tags.length) return;
      const lyric = line.replace(/\[[^\]]+\]/g, "").trim();
      if (!lyric) return;
      tags.forEach((tag) => {
        const minutes = Number(tag[1]);
        const seconds = Number(tag[2]);
        const fraction = String(tag[3] || "0");
        const millis = Number(fraction.padEnd(3, "0").slice(0, 3));
        const time = minutes * 60 + seconds + millis / 1000;
        if (Number.isFinite(time)) rows.push({ time, text: lyric });
      });
    });
    return rows
      .sort((left, right) => left.time - right.time)
      .filter((row, index, list) => index === 0 || row.time !== list[index - 1].time || row.text !== list[index - 1].text);
  },
  extractCurrentLyricsRawText(queueItem = null) {
    const currentQueueItem = queueItem || {};
    const media = currentQueueItem.media_item || {};
    const metadata = media.metadata || currentQueueItem.metadata || {};
    const candidates = [
      currentQueueItem.lyrics,
      currentQueueItem.plainLyrics,
      currentQueueItem.plain_lyrics,
      currentQueueItem.syncedLyrics,
      currentQueueItem.synced_lyrics,
      media.lyrics,
      media.plainLyrics,
      media.plain_lyrics,
      media.syncedLyrics,
      media.synced_lyrics,
      metadata.lyrics,
      metadata.plainLyrics,
      metadata.plain_lyrics,
      metadata.syncedLyrics,
      metadata.synced_lyrics,
    ];
    for (const candidate of candidates) {
      const text = HomeiiMediaPresentationFoundation.coerceLyricsRawText(candidate);
      if (text) return text;
    }
    return "";
  },
  extractCurrentLyricsText(queueItem = null) {
    return HomeiiMediaPresentationFoundation.stripLyricsTimestamps(
      HomeiiMediaPresentationFoundation.extractCurrentLyricsRawText(queueItem),
    );
  },
  imageProxyUrl(path, provider = "", size = 300, maUrl = "") {
    if (!path) return null;
    if (/^(https?:|data:|blob:)/i.test(path)) return path;
    if (String(path).startsWith("/")) return String(path);
    if (!maUrl) return null;
    const providerKey = provider || "";
    return `${maUrl}/imageproxy?path=${encodeURIComponent(path)}${providerKey ? `&provider=${encodeURIComponent(providerKey)}` : ""}&size=${size}`;
  },
  imageUrl(value, size = 300, { maUrl = "", seen = new Set(), depth = 0 } = {}) {
    if (!value || depth > 5) return null;
    if (typeof value === "string") {
      const raw = String(value).trim();
      if (!raw) return null;
      if (/^(https?:|data:|blob:)/i.test(raw)) return raw;
      if (raw.startsWith("/")) return raw;
      if (raw.startsWith("imageproxy?")) return `/${raw}`;
      if (raw.startsWith("imageproxy/")) return `/${raw}`;
      if (raw.includes("/imageproxy?")) return raw;
      return HomeiiMediaPresentationFoundation.imageProxyUrl(raw, "", size, maUrl);
    }
    if (typeof value !== "object") return null;
    if (seen.has(value)) return null;
    seen.add(value);
    if (Array.isArray(value)) {
      for (const entry of value) {
        const resolved = HomeiiMediaPresentationFoundation.imageUrl(entry, size, { maUrl, seen, depth: depth + 1 });
        if (resolved) return resolved;
      }
      return null;
    }
    if (value.url) return value.url;
    const rawPath = value.path || value.image_path || value.thumb_path || value.cover_path;
    if (rawPath) {
      return HomeiiMediaPresentationFoundation.imageProxyUrl(
        rawPath,
        value.provider || value.provider_id || value.provider_instance || value.provider_domain || value.provider_name || "",
        size,
        maUrl,
      );
    }
    const priorityKeys = [
      "image",
      "images",
      "image_url",
      "imageUrl",
      "thumb",
      "thumbnail",
      "small",
      "medium",
      "large",
      "cover",
      "cover_image",
      "artwork",
      "picture",
      "fanart",
      "square",
      "album",
      "media_item",
      "metadata",
    ];
    for (const key of priorityKeys) {
      const resolved = HomeiiMediaPresentationFoundation.imageUrl(value[key], size, { maUrl, seen, depth: depth + 1 });
      if (resolved) return resolved;
    }
    for (const entry of Object.values(value)) {
      if (!entry || typeof entry !== "object") continue;
      const resolved = HomeiiMediaPresentationFoundation.imageUrl(entry, size, { maUrl, seen, depth: depth + 1 });
      if (resolved) return resolved;
    }
    return null;
  },
  artUrl(item = null, maUrl = "") {
    return HomeiiMediaPresentationFoundation.imageUrl(item?.image_url, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.image, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.thumbnail, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.thumb, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.cover, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.media_image, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.media_item?.image_url, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.media_item?.image, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.media_item?.metadata?.images, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.album?.image_url, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.album?.image, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.metadata?.images, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item?.album?.metadata?.images, 300, { maUrl })
      || HomeiiMediaPresentationFoundation.imageUrl(item, 300, { maUrl })
      || null;
  },
  artistName(item = null) {
    return Array.isArray(item?.artists) ? item.artists.map((artist) => artist?.name).join(", ") : "";
  },
  formatDuration(sec) {
    if (!sec || Number.isNaN(sec)) return "0:00";
    const total = Math.floor(sec);
    const minutes = Math.floor(total / 60);
    const seconds = String(total % 60).padStart(2, "0");
    return `${minutes}:${seconds}`;
  },
  normalizeMediaItem(item, maUrl = "") {
    if (!item || typeof item !== "object") return item;
    const imageUrl = HomeiiMediaPresentationFoundation.artUrl(item, maUrl);
    return imageUrl && item.image_url !== imageUrl ? { ...item, image_url: imageUrl } : item;
  },
});

const HomeiiMediaHistoryFoundation = Object.freeze({
  buildCurrentSourceBadgeMeta(
    {
      player = null,
      queueItem = null,
    } = {},
    {
      parseMediaReferenceFn = HomeiiMediaQueueFoundation.parseMediaReference,
      sourceProviderMetaFn = HomeiiMediaPresentationFoundation.sourceProviderMeta,
      qualityBadgeLabelFn = HomeiiMediaPresentationFoundation.qualityBadgeLabel,
      libraryLabel = "Library",
      radioLabel = "Radio",
    } = {},
  ) {
    const currentQueueItem = queueItem || null;
    const media = currentQueueItem?.media_item || currentQueueItem || {};
    const parsed = parseMediaReferenceFn(
      media?.uri || currentQueueItem?.uri || currentQueueItem?.media_content_id || player?.attributes?.media_content_id || "",
      media?.media_type || currentQueueItem?.media_type || player?.attributes?.media_content_type || "track",
    );
    const mappings = []
      .concat(Array.isArray(media?.provider_mappings) ? media.provider_mappings : [])
      .concat(Array.isArray(currentQueueItem?.provider_mappings) ? currentQueueItem.provider_mappings : []);
    const providerCandidates = [
      media?.provider,
      media?.provider_name,
      media?.provider_domain,
      media?.provider_instance,
      currentQueueItem?.provider,
      currentQueueItem?.provider_name,
      currentQueueItem?.provider_domain,
      currentQueueItem?.provider_instance,
      player?.attributes?.provider,
      player?.attributes?.provider_name,
      parsed.provider,
      ...mappings.flatMap((mapping) => [mapping?.provider, mapping?.provider_domain, mapping?.provider_instance, mapping?.provider_name]),
    ].filter(Boolean);
    const providerMeta = providerCandidates
      .map((value) => sourceProviderMetaFn(value, { libraryLabel, radioLabel }))
      .find(Boolean) || null;
    const qualityLabel = qualityBadgeLabelFn([
      media?.audio_format,
      media?.quality,
      media?.streamdetails,
      media?.metadata,
      currentQueueItem?.audio_format,
      currentQueueItem?.quality,
      currentQueueItem?.streamdetails,
      currentQueueItem?.metadata,
      player?.attributes?.media_codec,
      player?.attributes?.media_format,
      ...mappings.map((mapping) => mapping?.details),
      ...mappings.map((mapping) => mapping?.quality),
      ...mappings.map((mapping) => mapping?.audio_format),
    ]);
    return {
      providerKey: providerMeta?.key || "",
      providerLabel: providerMeta?.label || "",
      qualityLabel,
    };
  },
  buildCurrentHistorySnapshot(
    {
      player = null,
      queueItem = null,
    } = {},
    {
      getQueueItemUriFn,
      queueItemImageUrlFn,
      artUrlFn,
      buildCurrentSourceBadgeMetaFn = HomeiiMediaHistoryFoundation.buildCurrentSourceBadgeMeta,
    } = {},
  ) {
    const currentQueueItem = queueItem || null;
    const media = currentQueueItem?.media_item || currentQueueItem || {};
    const title = media?.name || currentQueueItem?.name || player?.attributes?.media_title || "";
    const artist = Array.isArray(media?.artists)
      ? media.artists.map((entry) => entry?.name).filter(Boolean).join(", ")
      : (media?.artist_str || player?.attributes?.media_artist || "");
    const album = media?.album?.name || currentQueueItem?.album || player?.attributes?.media_album_name || "";
    const uri = String(getQueueItemUriFn?.(currentQueueItem) || media?.uri || player?.attributes?.media_content_id || "").trim();
    const mediaType = String(media?.media_type || currentQueueItem?.media_type || player?.attributes?.media_content_type || "track").toLowerCase();
    const key = [title, artist, album].map((part) => String(part || "").trim().toLowerCase()).join("|");
    if (!key || !uri || mediaType === "radio") return null;
    const sourceMeta = buildCurrentSourceBadgeMetaFn({ player, queueItem: currentQueueItem });
    return {
      key,
      uri,
      media_type: mediaType || "track",
      title,
      artist,
      album,
      image: queueItemImageUrlFn?.(currentQueueItem, 180) || artUrlFn?.(media) || artUrlFn?.(currentQueueItem) || "",
      provider_label: sourceMeta.providerLabel || "",
      quality_label: sourceMeta.qualityLabel || "",
    };
  },
  applyRecentPlaybackSnapshot(snapshot = null, previousEntry = null, recentHistory = [], maxItems = 10) {
    if (!snapshot) {
      return {
        currentEntry: previousEntry || null,
        recentHistory: Array.isArray(recentHistory) ? recentHistory : [],
        historyChanged: false,
      };
    }
    if (previousEntry?.key === snapshot.key && previousEntry?.uri === snapshot.uri) {
      return {
        currentEntry: snapshot,
        recentHistory: Array.isArray(recentHistory) ? recentHistory : [],
        historyChanged: false,
      };
    }
    if (previousEntry?.uri && previousEntry?.key && previousEntry.key !== snapshot.key) {
      const next = [
        previousEntry,
        ...((Array.isArray(recentHistory) ? recentHistory : []).filter((entry) => entry?.uri && entry.uri !== previousEntry.uri && entry.key !== snapshot.key)),
      ].slice(0, maxItems);
      return {
        currentEntry: snapshot,
        recentHistory: next,
        historyChanged: true,
      };
    }
    return {
      currentEntry: snapshot,
      recentHistory: Array.isArray(recentHistory) ? recentHistory : [],
      historyChanged: false,
    };
  },
  visibleRecentHistoryItems(currentEntry = null, recentHistory = [], limit = 10) {
    const currentKey = currentEntry?.key || "";
    return (Array.isArray(recentHistory) ? recentHistory : [])
      .filter((entry) => entry?.uri && entry?.key && entry.key !== currentKey)
      .slice(0, limit);
  },
  mediaFeedbackLabel(
    uri = "",
    fallback = "",
    queueItems = [],
    {
      getQueueItemUriFn,
      defaultLabel = "Media",
    } = {},
  ) {
    const text = String(fallback || "").trim();
    if (text) return text;
    const normalizedUri = String(uri || "").trim();
    if (!normalizedUri) return defaultLabel;
    const queueHit = (Array.isArray(queueItems) ? queueItems : []).find((item) => getQueueItemUriFn?.(item) === normalizedUri);
    if (queueHit?.media_item?.name) return queueHit.media_item.name;
    const separator = normalizedUri.lastIndexOf("/");
    if (separator >= 0 && separator < normalizedUri.length - 1) return decodeURIComponent(normalizedUri.slice(separator + 1));
    return normalizedUri;
  },
});

